var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"어서 오세요, 경정님. 오늘도 일찍 나오셨네요.","JPN":"おはようございます、警視様。今日も早いですね。","ENG":"Good morning, Major. You're early as usual.","TWN":"歡迎，警正大人，今天也好早啊。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경찰이라면 당연히 시간을 준수해야지.","JPN":"警察官たる者、時間は厳守しないと。","ENG":"I'm a police officer: I must be punctual.","TWN":"警察當然要守時了。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그런데 그 포스터는 다 뭐야?","JPN":"ところで、そのポスターはなに？","ENG":"By the way, what are those posters?","TWN":"那些海報是什麼？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"이번에 저희가 붙이러 다녀야 될 현상수배서죠.","JPN":"今から私たちが貼らなければならない指名手配書です。","ENG":"Wanted posters, for you and I to put up out there today.","TWN":"是我們這次要張貼的懸賞通緝令。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"리플레이서 사태 이후로 인력이 없어서 지지부진한 사건들이 꽤 늘었잖아요.","JPN":"リプレイサーの事件以降、人手不足で\\n捜査が進まない事件がかなり増えてきたじゃないですか。","ENG":"Since the Replacer incident, we've been slow at solving crimes due to a lack of manpower.","TWN":"克隆事件發生後，我們人手不足，導致很多案件毫無進展。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그 얘기는 들었어. 시민들의 협조를 받으려고 한단 말이지.","JPN":"その話は聞いた。それで市民に協力を求めるわけね。","ENG":"So I've heard. And that's why we're going to ask the citizens for help.","TWN":"這我也聽說了，是想要尋求市民的幫助吧。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......그런데 인력이 부족하다면서 우리는 왜 수배서나 붙이러 다녀야 되는 거야?","JPN":"……ところで、人手不足だと言ってるのに\\nなんで指名手配書なんか貼りに行かなきゃならないの？","ENG":"But if manpower is the problem, shouldn't we use ours to solve crimes, rather than putting up these posters?","TWN":"……可是妳都說人手不足了，為什麼我們還要去貼通緝令呢？"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"그야 이런 일로 농땡이 피워야 무서운 악당들이랑 싸우는 데 안 끌려 가니까요.","JPN":"この仕事を口実にしておくと、怖い悪党と戦う現場に\\n呼び出されなくて済むんです。","ENG":"Nope. We need this, to avoid getting dragged into fights with scary villains.","TWN":"因為這樣就可以偷懶，不用去和可怕的壞人戰鬥了啊。"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"자자, 경정님도 오셨겠다 얼른 가죠!","JPN":"さあ、警視様も出勤したことですし、早く行きましょう！","ENG":"Alright, now that you're here, let's go!","TWN":"好了，警正大人既然也來了，那我們快出發吧！"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"거기 서지 못해! 강소영 경위!","JPN":"待ちなさい！　マエカワ警部補！","ENG":"Stop right there! Lieutenant Kang!","TWN":"站住！姜素英警衛！"},"stage":{"bg":"OFFICE_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>연쇄 동물 납치범을 찾습니다. 실종된 동물들을 목격하신 분은 관할 경찰서로 연락 주세요</color>......","JPN":"<color=#ffd34c>連続動物拉致事件の容疑者を捜しています。\\n失踪した動物たちを目撃した方は管轄の警察署までご連絡ください</color>……","ENG":"<color=#ffd34c>Wanted: A serial animal abductor. If you believe you've witnessed animal abduction, please contact your local police station</color>...","TWN":"<color=#ffd34c>尋找動物連環綁架犯。若目擊到失蹤的動物，請聯絡管轄區的警察局</color>……"},"stage":{"bg":"CLASS","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"호진 언니, 이 포스터 어디서 났어요?","JPN":"マユミさん、このポスターどこでもらいました？","ENG":"Hojin, where did you get this poster?","TWN":"鎬眞姐，這個海報是從哪來的？"},"stage":{"bg":"CLASS","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"우리 동네 여기저기에 잔뜩 붙어 있었어.","JPN":"そこでもらったの。街のあちこちにいっぱい貼られてたから。","ENG":"It was put up here and there in the neighborhood.","TWN":"我們家附近到處都貼滿了這個海報。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"어른들이 그러는데 며칠 전에 알렉산더도 사라졌대.","JPN":"大人たちが言ってたけど、数日前にアレクサンダーも消えたって。","ENG":"Some grownups said that Alexander also disappeared a few days ago.","TWN":"我聽大人們說，幾天前，亞歷山大也失蹤了。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SORIM_REBBIT_NULL_NULL","text":{"KOREA":"알렉산더는 누군가, 호진 대원?","JPN":"マユミ隊員、アレクサンダーとは誰のことだ？","ENG":"Who's this Alexander, Operative Hojin?","TWN":"亞歷山大是誰啊，鎬眞隊員？"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"야채 가게 할아버지가 키우는 웰시 코기. 우리 동네 귀여움 일등이야.","JPN":"八百屋のおじいさんが飼ってるウェルシュ・コーギーだよ。\\nこの街で一番可愛いの。","ENG":"The greengrocer's Welsh Corgi. He's the cutest thing in the neighborhood.","TWN":"是蔬菜店爺爺養的一隻柯基犬，在我們街上是超級可愛的狗狗。"},"stage":{"bg":"CLASS","slots":{"L":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};